module top_module(
  input clk,
  input reset,
  input count_dir,
  input [31:0] max_count,
  output [31:0] count,
  output reg overflow  // Change here: 'overflow' is now declared as a reg
);reg [31:0] count_reg;
  wire [31:0] count_next;

    wire _n01 = count_reg[0] ^ (count_dir ? 1 : -1)[0];
  wire _c01 = count_reg[0] & (count_dir ? 1 : -1)[0];
  wire _n02 = count_reg[1] ^ (count_dir ? 1 : -1)[1] ^ _c01;
  wire _c02 = (count_reg[1] & (count_dir ? 1 : -1)[1]) | (count_reg[1] & _c01) | ((count_dir ? 1 : -1)[1] & _c01);
  wire _n03 = count_reg[2] ^ (count_dir ? 1 : -1)[2] ^ _c02;
  wire _c03 = (count_reg[2] & (count_dir ? 1 : -1)[2]) | (count_reg[2] & _c02) | ((count_dir ? 1 : -1)[2] & _c02);
  wire _n04 = count_reg[3] ^ (count_dir ? 1 : -1)[3] ^ _c03;
  wire _c04 = (count_reg[3] & (count_dir ? 1 : -1)[3]) | (count_reg[3] & _c03) | ((count_dir ? 1 : -1)[3] & _c03);
  assign count_next = {_n01, _n02, _n03, _n04};

  always @(posedge clk) begin
    if (reset) begin
      count_reg <= 0;
      overflow <= 0; // Now valid as 'overflow' is a reg
    end else begin
      count_reg <= (count_next <= max_count) ? count_next : 0;
      overflow <= (count_next > max_count); // Now valid as 'overflow' is a reg
    end
  end

  assign count = count_reg;

endmodule
